request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?model
  ?modelName
  ?created
  ?originalId
  ?normalizedId
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .

  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }

  # "parallel execution": a choreography containing a ParallelGateway
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .
  ?pg a bboExt:ParallelGateway ;
      tai:belongsTo ?choreo .
}
ORDER BY DESC(?created)
LIMIT 25
